const jwt = require('jsonwebtoken');
const axios = require('axios');

async function validateJwt(token, issuer, audience, jwksEndpoint) {
  // Fetch JSON Web Key Set (JWKS) from the specified endpoint
  const response = await axios.get(jwksEndpoint);
  const jwks = response.data;

  // Extract the key ID (kid) from the token header
  const decodedToken = jwt.decode(token, { complete: true });
  const kid = decodedToken.header.kid;

  // Find the matching JSON Web Key (JWK) in the JWKS
  const jwk = jwks.keys.find(key => key.kid === kid);

  // If no matching JWK is found, throw an error
  if (!jwk) {
    throw new Error('No matching JWK found');
  }

  // Verify the token signature using the RS256 algorithm
  const pem = jwkToPem(jwk);
  try {
    jwt.verify(token, pem, { issuer, audience, algorithms: ['RS256'] });
  } catch (error) {
    throw new Error('Invalid token signature');
  }

  // Check if the token has expired
  if (decodedToken.payload.exp < Date.now() / 1000) {
    throw new Error('Token has expired');
  }
}

// Helper function to convert JWK to PEM
function jwkToPem(jwk) {
  const { n, e } = jwk;
  const pem = `-----BEGIN RSA PUBLIC KEY-----
MIIBCgKCAQEA${Buffer.from(n, 'base64url').toString('base64')}${Buffer.from(e, 'base64url').toString('base64')}
-----END RSA PUBLIC KEY-----`;
  return pem;
}

// Example usage
async function main() {
  try {
    await validateJwt('your_jwt_token', 'https://example.com', 'your_audience', 'https://example.com/.well-known/jwks.json');
    console.log('Token is valid');
  } catch (error) {
    console.error('Token is invalid:', error.message);
  }
}

main();
